// components/ui/Preview/PreviewApp.tsx
"use client";
import { MDXRemoteSerializeResult } from "next-mdx-remote";
import { usePathname } from "next/navigation";
import { useState } from "react";
import {
  CodeBlock,
  Component,
  ComponentCards,
  ComponentDetails,
} from "types/types";
import Preview from ".";

interface ComponentData extends Component, ComponentDetails, CodeBlock {
  mdxSource: MDXRemoteSerializeResult;
}

interface Props {
  components: ComponentData[];
}

export default ({ components }: Props) => {
  const pathname = usePathname();

  return (
    <>
      {components?.map((item: ComponentData, idx: number) =>
        item.isActive ? (
          <div key={idx}>
            <Preview item={item} mdxSource={item.mdxSource} slug={pathname} />
          </div>
        ) : (
          ""
        )
      )}
    </>
  );
};

